USE rehab_center_db;
GO

SET NOCOUNT ON;
GO

/* 1. Xoa du lieu seed cu theo dung thu tu khoa ngoai */
DELETE FROM NhatKyDieuTri WHERE MaChiTietPhacDo LIKE 'TPA-CT%';
DELETE FROM ChiTietPhacDoDieuTri WHERE MaChiTietPhacDo LIKE 'TPA-CT%';
DELETE FROM PhacDoDieuTri WHERE MaPhacDoDT LIKE 'TPA-PD%';
DELETE FROM HoSoBenhAn WHERE MaBenhAn LIKE 'TPA-BA%';
DELETE FROM PhanCongPhuTrach WHERE MaPhanCong LIKE 'TPA-PC%';
DELETE FROM NguoiCaiNghien WHERE MaNguoiCaiNghien LIKE 'TPA-NCN%';
DELETE FROM HoSoBanGiao WHERE MaHoSoBanGiao LIKE 'TPA-HSBG%';
DELETE FROM CanBoQuanLyHoSo WHERE MaCanBoCongAn = 'TPA-CA01';
DELETE FROM NhanSu WHERE MaNhanSu IN ('TPA-QL01','TPA-BS01','TPA-BS02','TPA-NV01');
DELETE FROM NguoiThan WHERE MaNguoiDung IN (SELECT MaNguoiDung FROM NguoiDung WHERE TenDangNhap LIKE 'tpa_%');
DELETE FROM NguoiDung WHERE TenDangNhap LIKE 'tpa_%';
GO

