/* 5. Query kiem tra nhanh du lieu cho giao dien phe duyet phac do */
SELECT TrangThai, COUNT(*) AS SoLuong
FROM ChiTietPhacDoDieuTri
WHERE MaChiTietPhacDo LIKE 'TPA-CT%'
GROUP BY TrangThai
ORDER BY CASE TrangThai WHEN 'CHO_PHE_DUYET' THEN 1 WHEN 'DANG_AP_DUNG' THEN 2 WHEN 'TU_CHOI' THEN 3 WHEN 'TAM_DUNG' THEN 4 WHEN 'DA_HOAN_THANH' THEN 5 ELSE 6 END;

SELECT TOP 50
    ct.MaChiTietPhacDo AS detailPlanId,
    pd.MaPhacDoDT AS treatmentPlanId,
    ba.MaBenhAn AS medicalRecordId,
    ncn.MaNguoiCaiNghien AS patientId,
    ncn.HoTen AS patientName,
    gd.TenGiaiDoan AS stageName,
    ct.ThuTu AS stageOrder,
    pd.LoaiMaTuy AS drugType,
    ct.NoiDungPhacDoDT AS treatmentContent,
    ct.MucTieu AS goal,
    ct.NgayBatDau AS startDate,
    ct.NgayKetThucDuKien AS expectedEndDate,
    ct.TrangThai AS status,
    ct.MaQuanLy AS managerId,
    ct.NgayPheDuyet AS approvedAt,
    ct.GhiChuPheDuyet AS approvalNote
FROM ChiTietPhacDoDieuTri ct
JOIN PhacDoDieuTri pd ON ct.MaPhacDoDT = pd.MaPhacDoDT
JOIN HoSoBenhAn ba ON pd.MaBenhAn = ba.MaBenhAn
LEFT JOIN NguoiCaiNghien ncn ON ba.MaNguoiCaiNghien = ncn.MaNguoiCaiNghien
LEFT JOIN DanhMucGiaiDoan gd ON ct.MaGiaiDoan = gd.MaGiaiDoan
WHERE ct.MaChiTietPhacDo LIKE 'TPA-CT%'
ORDER BY CASE ct.TrangThai WHEN 'CHO_PHE_DUYET' THEN 1 WHEN 'DANG_AP_DUNG' THEN 2 WHEN 'TU_CHOI' THEN 3 ELSE 4 END, ct.NgayBatDau DESC;
GO
