INSERT INTO ChiTietPhacDoDieuTri (MaChiTietPhacDo, MaPhacDoDT, MaGiaiDoan, ThuTu, NoiDungPhacDoDT, MucTieu, NgayBatDau, NgayKetThucDuKien, TrangThai, MaQuanLy, NgayPheDuyet, GhiChuPheDuyet) VALUES
('TPA-CT001-G1', 'TPA-PD001', 'GD001', 1, N'Khám đánh giá ban đầu, theo dõi hội chứng cai, hỗ trợ ổn định thể chất và hướng dẫn nội quy điều trị trong tuần đầu. Loại chất sử dụng chính: HEROIN. Bác sĩ đề xuất theo dõi sát biểu hiện thể chất, tâm lý và mức độ hợp tác của học viên trong từng buổi sinh hoạt.', N'Ổn định thể trạng, giảm triệu chứng cai cấp, bảo đảm người cai nghiện hợp tác với phác đồ. Mục tiêu bổ sung: giảm nguy cơ tái nghiện, tăng khả năng tuân thủ nội quy và chuẩn bị đánh giá định kỳ.', DATEADD(day, -39, GETDATE()), DATEADD(day, 59, GETDATE()), 'CHO_PHE_DUYET', NULL, NULL, NULL),
('TPA-CT001-G2', 'TPA-PD001', 'GD002', 2, N'Tư vấn tâm lý cá nhân, tham gia sinh hoạt nhóm, lao động trị liệu nhẹ và theo dõi đáp ứng điều trị hằng tuần. Loại chất sử dụng chính: HEROIN. Bác sĩ đề xuất theo dõi sát biểu hiện thể chất, tâm lý và mức độ hợp tác của học viên trong từng buổi sinh hoạt.', N'Phục hồi sức khỏe, điều chỉnh hành vi, nâng cao nhận thức về tác hại của chất gây nghiện. Mục tiêu bổ sung: giảm nguy cơ tái nghiện, tăng khả năng tuân thủ nội quy và chuẩn bị đánh giá định kỳ.', DATEADD(day, -25, GETDATE()), DATEADD(day, 45, GETDATE()), 'CHO_PHE_DUYET', NULL, NULL, NULL),
('TPA-CT001-G3', 'TPA-PD001', 'GD003', 3, N'Xây dựng kế hoạch tái hòa nhập, tư vấn gia đình, đánh giá nguy cơ tái nghiện và chuẩn bị hồ sơ hoàn thành. Loại chất sử dụng chính: HEROIN. Bác sĩ đề xuất theo dõi sát biểu hiện thể chất, tâm lý và mức độ hợp tác của học viên trong từng buổi sinh hoạt.', N'Chuẩn bị kỹ năng sống, kết nối gia đình, giảm nguy cơ tái nghiện sau khi rời trung tâm. Mục tiêu bổ sung: giảm nguy cơ tái nghiện, tăng khả năng tuân thủ nội quy và chuẩn bị đánh giá định kỳ.', DATEADD(day, -11, GETDATE()), DATEADD(day, 31, GETDATE()), 'CHO_PHE_DUYET', NULL, NULL, NULL),
('TPA-CT002-G1', 'TPA-PD002', 'GD001', 1, N'Khám đánh giá ban đầu, theo dõi hội chứng cai, hỗ trợ ổn định thể chất và hướng dẫn nội quy điều trị trong tuần đầu. Loại chất sử dụng chính: MA TUY DA. Bác sĩ đề xuất theo dõi sát biểu hiện thể chất, tâm lý và mức độ hợp tác của học viên trong từng buổi sinh hoạt.', N'Ổn định thể trạng, giảm triệu chứng cai cấp, bảo đảm người cai nghiện hợp tác với phác đồ. Mục tiêu bổ sung: giảm nguy cơ tái nghiện, tăng khả năng tuân thủ nội quy và chuẩn bị đánh giá định kỳ.', DATEADD(day, -38, GETDATE()), DATEADD(day, 58, GETDATE()), 'CHO_PHE_DUYET', NULL, NULL, NULL),
('TPA-CT002-G2', 'TPA-PD002', 'GD002', 2, N'Tư vấn tâm lý cá nhân, tham gia sinh hoạt nhóm, lao động trị liệu nhẹ và theo dõi đáp ứng điều trị hằng tuần. Loại chất sử dụng chính: MA TUY DA. Bác sĩ đề xuất theo dõi sát biểu hiện thể chất, tâm lý và mức độ hợp tác của học viên trong từng buổi sinh hoạt.', N'Phục hồi sức khỏe, điều chỉnh hành vi, nâng cao nhận thức về tác hại của chất gây nghiện. Mục tiêu bổ sung: giảm nguy cơ tái nghiện, tăng khả năng tuân thủ nội quy và chuẩn bị đánh giá định kỳ.', DATEADD(day, -24, GETDATE()), DATEADD(day, 44, GETDATE()), 'TU_CHOI', 'TPA-QL01', DATEADD(day, -3, GETDATE()), N'Chưa đủ căn cứ đánh giá hoặc nội dung phác đồ cần bác sĩ bổ sung thêm mục tiêu, thời gian theo dõi và hướng xử lý khi có biểu hiện bất thường.'),
